#!/usr/bin/env python3
# Patch the landing page HTML with the embedded badge
with open('/mnt/user-data/outputs/shefa-landing-page-v2.html', 'r', encoding='utf-8') as f:
    html = f.read()

old_tag = '<img class="partner-badge" src="https://business.yelp.com/wp-content/uploads/2026/01/platinum-partner-logo-170x170-1.webp" alt="Yelp Platinum Advertising Partner" width="200" height="200">'
new_tag = '<img class="partner-badge" src="data:image/png;base64," alt="Yelp Platinum Advertising Partner" width="200" height="200">'

if old_tag in html:
    html = html.replace(old_tag, new_tag)
    with open('/mnt/user-data/outputs/shefa-landing-page-v2.html', 'w', encoding='utf-8') as f:
        f.write(html)
    print("SUCCESS: badge embedded, file updated")
else:
    print("ERROR: old tag not found in HTML")
    # show what the current img tag looks like
    import re
    matches = re.findall(r'<img class="partner-badge"[^>]+>', html)
    print("Found img tags:", matches)
